-- ============================================================
-- SgSL Hub: signLibrary table setup + data restore
-- Run this in your Supabase SQL Editor (Dashboard > SQL Editor)
-- ============================================================

-- 1. Create the signLibrary table
CREATE TABLE IF NOT EXISTS public."signLibrary" (
    id uuid DEFAULT gen_random_uuid() NOT NULL,
    label text DEFAULT ''::text NOT NULL,
    filename text DEFAULT ''::text NOT NULL,
    created_at timestamp with time zone DEFAULT now() NOT NULL,
    landmarks jsonb,
    features jsonb,
    CONSTRAINT "signLibrary_pkey" PRIMARY KEY (id)
);

COMMENT ON TABLE public."signLibrary" IS 'Collection of SgSL Signs';

-- 2. Enable Row Level Security
ALTER TABLE public."signLibrary" ENABLE ROW LEVEL SECURITY;

-- 3. Create RLS policies for anon access
CREATE POLICY "Allow anon inserts" ON public."signLibrary"
    FOR INSERT WITH CHECK (true);

CREATE POLICY "Allow anon selects" ON public."signLibrary"
    FOR SELECT USING (true);

-- 4. Grant permissions
GRANT ALL ON TABLE public."signLibrary" TO anon;
GRANT ALL ON TABLE public."signLibrary" TO authenticated;
GRANT ALL ON TABLE public."signLibrary" TO service_role;

-- 5. Insert backup data

